import { describe, expect, it } from 'vitest';
import { classifyTutoringEvent } from '../../src/tutor/safety_monitor';

describe('classifyTutoringEvent', () => {
  it('escalates lesson drift attempts', () => {
    const result = classifyTutoringEvent({ type: 'lesson_drift', sessionId: 'sess-1' });
    expect(result.band).toBe('escalate');
  });

  it('marks routine lesson progress as routine', () => {
    const result = classifyTutoringEvent({ type: 'progress_update', sessionId: 'sess-1' });
    expect(result.band).toBe('routine');
  });
});

target_file_skeleton:
export type SafetyBand = 'routine' | 'review' | 'escalate';

export interface SafetyDecision {
  sessionId: string;
  band: SafetyBand;
  reason: string;
}

export function classifyTutoringEvent(input: { type: string; sessionId: string }): SafetyDecision {
  return { sessionId: input.sessionId, band: 'routine', reason: input.type };
}
